import { OpenAI } from 'openai';
import { VexClient, SchemaValidator } from 'vex-sdk';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
const vex = new VexClient({ apiKey: process.env.VEX_API_KEY });

// Your function schemas — same ones registered with the assistant
const functionSchemas: Record<string, object> = {
  reserve_seat: {
    type: 'object',
    properties: {
      flight_id: { type: 'string', pattern: '^FL-[0-9]{6}$' },
      seat_class: { type: 'string', enum: ['economy', 'business', 'first'] },
      passenger_count: { type: 'integer', minimum: 1, maximum: 9 }
    },
    required: ['flight_id', 'seat_class', 'passenger_count']
  }
};

async function handleRequiresAction(
  threadId: string,
  runId: string,
  requiredAction: OpenAI.Beta.Runs.RequiredAction
) {
  const toolCalls = requiredAction.submit_tool_outputs.tool_calls;
  const toolOutputs: OpenAI.Beta.Threads.Runs.RunSubmitToolOutputsParams.ToolOutput[] = [];

  for (const toolCall of toolCalls) {
    const fnName = toolCall.function.name;
    const args = JSON.parse(toolCall.function.arguments);

    // Validate args against schema using Vex before executing
    const validation = await vex.schema.validate({
      functionName: fnName,
      arguments: args,
      schema: functionSchemas[fnName],
      policyName: 'assistants-api-policy'
    });

    if (!validation.valid) {
      console.error(`Vex blocked hallucinated args for ${fnName}:`, validation.errors);
      // Return an error tool output instead of executing with bad args
      toolOutputs.push({
        tool_call_id: toolCall.id,
        output: JSON.stringify({ error: 'Invalid arguments detected', details: validation.errors })
      });
      continue;
    }

    // Safe to execute — call your actual function
    const result = await dispatchFunction(fnName, args);
    toolOutputs.push({ tool_call_id: toolCall.id, output: JSON.stringify(result) });
  }

  // Submit validated tool outputs back to the run
  await openai.beta.threads.runs.submitToolOutputs(threadId, runId, { tool_outputs: toolOutputs });
}

async function dispatchFunction(name: string, args: Record<string, unknown>) {
  // Your function dispatch logic here
  return { success: true };
}
